import type { AriaLabelingProps } from '../../core/types/a11y-props.js';
import type { BehaviorTrackingProps } from '../../core/types/behavior-tracking-props.js';
import type { DataTestId } from '../../core/types/data-props.js';
import type { MaskingProps } from '../../core/types/masking-props.js';
import type { StylingProps } from '../../core/types/styling-props.js';
import type { WithChildren } from '../../core/types/with-children.js';
/** @public */
export type SingleExpanded = string | number;
/** @public */
export type MultiExpanded = Array<string | number>;
/** @public */
export interface AccordionOwnProps<Multiple extends boolean> extends WithChildren, StylingProps, DataTestId, MaskingProps, AriaLabelingProps, BehaviorTrackingProps {
    /**
     * Determines whether multiple sections can be open at the same time.
     * @defaultValue false
     */
    multiple?: Multiple;
    /**
     * The position of the trigger that expands and collapses a section.
     * @defaultValue 'end'
     */
    triggerPosition?: 'start' | 'end';
    /**
     * Callback fired when a section is expanded/collapsed.
     */
    onExpandChange?: (value: OnChangeValue<Multiple>) => void;
    /**
     * If the accordion is interactive, the whole header is interactive and can open or close the accordion.
     * Otherwise, only the button is interactive
     * @defaultValue true
     */
    interactive?: boolean;
    /**
     * The color of the accordion.
     * Setting the color affects the button, label, content and divider color.
     * @defaultValue 'neutral'
     */
    color?: 'neutral' | 'primary' | 'success' | 'warning' | 'critical';
    /**
     * The size of the accordion.
     * @defaultValue 'default'
     */
    size?: 'default' | 'condensed';
    /**
     * Whether a divider is shown between the sections.
     * @defaultValue true
     */
    showDividers?: boolean;
}
/** @public */
export interface AccordionUncontrolledProps<Multiple extends boolean> {
    /**
     * Determines which sections are initially expanded in an uncontrolled scenario.
     * @defaultValue false
     */
    defaultExpanded?: Multiple extends true ? MultiExpanded : SingleExpanded;
    /**
     * Determines which sections expanded in a controlled scenario.
     */
    expanded?: never;
}
/** @public */
export interface AccordionControlledProps<Multiple extends boolean> {
    /**
     * Determines which sections are initially expanded in an uncontrolled scenario.
     */
    defaultExpanded?: never;
    /**
     * Determines which sections are expanded in a controlled scenario.
     */
    expanded: Multiple extends true ? MultiExpanded : SingleExpanded;
}
/** @public */
export type AccordionProps<Multiple extends boolean> = AccordionOwnProps<Multiple> & (AccordionControlledProps<Multiple> | AccordionUncontrolledProps<Multiple>);
/** @public */
export type OnChangeValue<Multiple extends boolean> = Multiple extends true ? MultiExpanded : SingleExpanded;
